.mrg-stack {
  --mrg-stack-gap: var(--mrg-semantic-space-stack-md);
  align-items: stretch;
  display: flex;
  flex-direction: column;
  gap: var(--mrg-stack-gap);
  min-inline-size: 0;
}

.mrg-stack > * {
  min-inline-size: 0;
  overflow-wrap: anywhere;
}

.mrg-stack[data-gap="none"] {
  --mrg-stack-gap: 0px;
}

.mrg-stack[data-gap="xs"] {
  --mrg-stack-gap: var(--mrg-semantic-space-stack-xs);
}

.mrg-stack[data-gap="sm"] {
  --mrg-stack-gap: var(--mrg-semantic-space-stack-sm);
}

.mrg-stack[data-gap="lg"] {
  --mrg-stack-gap: var(--mrg-semantic-space-stack-lg);
}

.mrg-stack[data-align="start"] {
  align-items: flex-start;
}

.mrg-stack[data-align="center"] {
  align-items: center;
}

.mrg-stack[data-align="end"] {
  align-items: flex-end;
}

.mrg-stack:is(ul, ol) {
  margin-block: 0;
  padding-inline-start: var(--mrg-semantic-space-stack-lg);
}

.mrg-stack:is(ul, ol)[data-list-style="none"] {
  list-style: none;
  padding-inline-start: 0;
}

import { createElement, forwardRef, type HTMLAttributes } from "react";

import "./stack.css";

export type StackGap = "none" | "xs" | "sm" | "md" | "lg";
export type StackAlign = "stretch" | "start" | "center" | "end";
export type StackElement = "div" | "section" | "ul" | "ol";
export type StackListStyle = "preserve" | "none";

export interface StackProps extends HTMLAttributes<HTMLElement> {
  /** A restricted native element set keeps layout separate from arbitrary polymorphism. */
  readonly element?: StackElement;
  readonly gap?: StackGap;
  readonly align?: StackAlign;
  /** Applies only to ul/ol roots; preserve keeps native markers and indentation. */
  readonly listStyle?: StackListStyle;
}

function joinStackClassName(className: string | undefined): string {
  return className === undefined || className.trim().length === 0
    ? "mrg-stack"
    : `mrg-stack ${className}`;
}

export const Stack = forwardRef<HTMLElement, StackProps>(function Stack(
  {
    align = "stretch",
    className,
    element = "div",
    gap = "md",
    listStyle = "preserve",
    ...nativeProps
  },
  forwardedRef,
) {
  return createElement(element, {
    ...nativeProps,
    ref: forwardedRef,
    className: joinStackClassName(className),
    "data-align": align,
    "data-element": element,
    "data-gap": gap,
    "data-list-style": listStyle,
    "data-slot": "stack",
  });
});

Stack.displayName = "Stack";
